17→pub fn list(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
18→    let (_workspace, repo) = common::load_repo(path)?;
19→
20→    let expression = RevsetExpression::all();
21→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
22→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
23→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
24→    let revset = resolved.evaluate(repo.as_ref())?;
25→
26→    let root_commit_id = repo.store().root_commit_id().clone();
27→
28→    for result in revset.iter() {
29→        let commit_id = result?;
30→        if commit_id == root_commit_id {
31→            continue;
32→        }
33→        let commit = repo.store().get_commit(&commit_id)?;
34→
35→        let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
36→        let change_short = &change_hex[..change_hex.len().min(12)];
37→
38→        let commit_hex = commit.id().hex();
39→        let commit_short = &commit_hex[..commit_hex.len().min(12)];
40→
41→        let first_line = commit.description().lines().next().unwrap_or("");
42→
43→        println!("{} {} {}", change_short, commit_short, first_line);
44→    }
45→
46→    Ok(())
47→}
